 const item = $input.first();
 const binaryKey = Object.keys(item.binary || {})[0] || 'data';
 const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);

 let text = '';
 try {
   let eocdOffset = -1;
   for (let i = buffer.length - 22; i >= 0; i--) {
     if (buffer.readUInt32LE(i) === 0x06054b50) { eocdOffset = i; break; }
   }
   if (eocdOffset === -1) throw new Error('Not a valid ZIP');

   const cdOffset = buffer.readUInt32LE(eocdOffset + 16);
   const cdEntries = buffer.readUInt16LE(eocdOffset + 10);
   const targets = ['xl/sharedStrings.xml', 'xl/worksheets/sheet1.xml'];
   const xmlContents = {};

   let pos = cdOffset;
   for (let i = 0; i < cdEntries; i++) {
     if (buffer.readUInt32LE(pos) !== 0x02014b50) break;
     const compressionMethod = buffer.readUInt16LE(pos + 10);
     const compressedSize = buffer.readUInt32LE(pos + 20);
     const fileNameLength = buffer.readUInt16LE(pos + 28);
     const extraLength = buffer.readUInt16LE(pos + 30);
     const commentLength = buffer.readUInt16LE(pos + 32);
     const localHeaderOffset = buffer.readUInt32LE(pos + 42);
     const fileName = buffer.toString('utf8', pos + 46, pos + 46 + fileNameLength);

     if (targets.includes(fileName)) {
       const localFileNameLen = buffer.readUInt16LE(localHeaderOffset + 26);
       const localExtraLen = buffer.readUInt16LE(localHeaderOffset + 28);
       const dataStart = localHeaderOffset + 30 + localFileNameLen + localExtraLen;
       const compressed = buffer.slice(dataStart, dataStart + compressedSize);

       let xml;
       if (compressionMethod === 8) {
         xml = inflate(compressed).toString('utf8');
       } else {
         xml = compressed.toString('utf8');
       }
       xmlContents[fileName] = xml;
       if (Object.keys(xmlContents).length === targets.length) break;
     }
     pos += 46 + fileNameLength + extraLength + commentLength;
   }

   if (xmlContents['xl/sharedStrings.xml']) {
     const matches = xmlContents['xl/sharedStrings.xml'].match(/<t[^>]*>([^<]*)<\/t>/g);
     if (matches) {
       text = matches.map(m => m.replace(/<[^>]*>/g, '')).join(' | ');
     }
   }
   if (!text && xmlContents['xl/worksheets/sheet1.xml']) {
     const matches = xmlContents['xl/worksheets/sheet1.xml'].match(/<v>([^<]*)<\/v>/g);
     if (matches) {
       text = matches.map(m => m.replace(/<[^>]*>/g, '')).join(' | ');
     }
   }
